     final seen = <String>{excludeUrl};
     final results = <AlternativeDetail>[];

+    // Match confidence by reason (how sure we are it's the same channel)
+    const _matchConfidence = <String, double>{
+      'vanity name': 1.0,
+      'tvgId': 0.95,
+      'EPG+call sign': 0.90,
+      'EPG': 0.65,
+      'call sign': 0.60,
+      'name': 0.50,
